<?php namespace App\Http\Controllers; use App\Enums\{Priority,WorkOrderStatus};use App\Http\Requests\WorkOrderRequest;use App\Models\{Asset,User,WorkOrder}; class WorkOrderController extends Controller{public function index(){return view('work-orders.index',['orders'=>WorkOrder::with('asset','technician')->latest()->paginate(12),'statuses'=>WorkOrderStatus::cases()]);} public function create(){return view('work-orders.form',['order'=>new WorkOrder,'assets'=>Asset::all(),'users'=>User::all(),'priorities'=>Priority::cases(),'statuses'=>WorkOrderStatus::cases()]);} public function store(WorkOrderRequest $r){$wo=WorkOrder::create($r->merge(['number'=>'WO-'.str_pad((string)(WorkOrder::count()+1),5,'0',STR_PAD_LEFT)])->all());return redirect()->route('work-orders.show',$wo)->with('toast','Work order created');} public function show(WorkOrder $work_order){$work_order->load('asset','technician','timeline');return view('work-orders.show',['order'=>$work_order]);} public function edit(WorkOrder $work_order){return view('work-orders.form',['order'=>$work_order,'assets'=>Asset::all(),'users'=>User::all(),'priorities'=>Priority::cases(),'statuses'=>WorkOrderStatus::cases()]);} public function update(WorkOrderRequest $r,WorkOrder $work_order){$work_order->update($r->all());return redirect()->route('work-orders.show',$work_order)->with('toast','Work order updated');} public function destroy(WorkOrder $work_order){$work_order->delete();return back()->with('toast','Work order deleted');}}
